// Verifica se veio dados do nó anterior
if ($input.first() === undefined) {
  return [{ json: { 
    erro: 'Nenhum dado recebido do nó anterior.', 
    timestamp: new Date().toISOString() 
  } }];
}

// Pega os dados extraídos do HTML
let precoExtraido = $input.first().json.preco;
let fechamentoAnterior = $input.first().json.fechamento_anterior;
let abertura = $input.first().json.abertura;

// Verifica se o preço foi encontrado
if (precoExtraido === undefined || precoExtraido === null || precoExtraido === '') {
  return [{ json: { 
    ativo: 'Milho (Investing.com)',
    erro: 'Preço não encontrado com nenhum seletor CSS. Estrutura do site pode ter mudado.',
    timestamp: new Date().toISOString(),
    status: 'erro'
  } }];
}

// Função para processar valores numéricos
function processarValor(valor) {
  if (!valor || valor === '') return null;

  try {
    let valorLimpo = valor
      .replace(/\s/g, '')
      .replace(/[R$]/g, '')
      .replace(/\./g, '')
      .replace(/,/g, '.');

    let valorNumerico = parseFloat(valorLimpo);
    return isNaN(valorNumerico) ? null : valorNumerico;
  } catch (error) {
    return null;
  }
}

// Tenta converter o preço
try {
  let precoNumerico = processarValor(precoExtraido);

  if (precoNumerico === null) {
    throw new Error('Conversão para número falhou: ' + precoExtraido);
  }

  // Processa fechamento anterior
  let fechamentoAnteriorNumerico = processarValor(fechamentoAnterior);

  // Processa abertura
  let aberturaNumerico = processarValor(abertura);

  return [{ json: {
    ativo: 'Milho (Investing.com)',
    preco: precoNumerico,
    preco_original: precoExtraido,
    fechamento_anterior: fechamentoAnteriorNumerico,
    fechamento_anterior_original: fechamentoAnterior,
    abertura: aberturaNumerico,
    abertura_original: abertura,
    moeda: 'BRL',
    fonte: 'Investing.com',
    timestamp: new Date().toISOString(),
    status: 'sucesso'
  } }];
} catch (error) {
  return [{ json: {
    ativo: 'Milho (Investing.com)',
    erro: 'Erro na conversão: ' + error.message,
    preco_original: precoExtraido,
    fechamento_anterior_original: fechamentoAnterior,
    abertura_original: abertura,
    timestamp: new Date().toISOString(),
    status: 'erro'
  } }];
}

try {
  const jsonResponse = $input.first().json;
  const originalData = $('⚙️ Processar Dados').first().json;

  if (jsonResponse.status === 'erro') {
    return [{
      json: {
        status: 'erro_json',
        erro: jsonResponse.erro,
        dados_originais: originalData,
        timestamp: new Date().toISOString()
      }
    }];
  }

  return [{
    json: {
      status: 'sucesso',
      mensagem: 'Dados salvos no JSON com sucesso',
      dados_salvos: originalData,
      arquivo: jsonResponse.arquivo,
      timestamp: new Date().toISOString()
    }
  }];

} catch (error) {
  return [{
    json: {
      status: 'erro_final',
      erro: 'Erro na resposta final: ' + error.message,
      timestamp: new Date().toISOString()
    }
  }];
}

try {
  // Coletar apenas os dados do milho
  const milho = $('💾 Salvar no JSON').first()?.json || null;

  // Estruturar JSON final apenas com milho
  const cotacoesConsolidadas = {
    metadata: {
      timestamp: new Date().toISOString(),
      data_coleta: new Date().toLocaleDateString('pt-BR'),
      total_ativos: milho ? 1 : 0,
      fonte: 'Investing.com'
    },
    commodities: {
      agricolas: {
        milho: milho?.dados_formatados?.dados || null
      }
    },
    status: {
      milho: milho?.status || 'erro'
    }
  };

  return [{ json: cotacoesConsolidadas }];

} catch (error) {
  return [{
    json: {
      erro: 'Erro ao consolidar cotações: ' + error.message,
      timestamp: new Date().toISOString(),
      status: 'erro_consolidacao'
    }
  }];
}

// Retornar o JSON consolidado final
