  const milho = $("💾 Salvar no Firebase7").first()?.json || null;
  const soja = $("💾 Salvar no Firebase8").first()?.json || null;

  if (!boiGordo || !milho || !soja) {
    return [
      {
        json: {
          erro: "Dados insuficientes",
          timestamp: new Date().toISOString(),
          status: "erro",
        },
      },
    ];
  }

  const rentBoiGordo = parseFloat(boiGordo.rent_media) || 0;
  const rentMilho = parseFloat(milho.rent_media) || 0;
  const rentSoja = parseFloat(soja.rent_media) || 0;

  // **Fatores conforme planilha original**
  const fatorBoi = 0.35; // B8
  const fatorMilho = 0.3; // D8
  const fatorSoja = 0.35; // F8
  const fatorArrendamento = 0.048; // F7

  // **Função para cálculos com precisão decimal**
  const precise = (num, decimals = 4) => {
    return Math.round(num * Math.pow(10, decimals)) / Math.pow(10, decimals);
  };

  // **Cálculo replicando exatamente a planilha Excel**
  // Primeiro multiplica por 25, depois aplica os fatores (como na planilha)
  const componenteBoi = precise(rentBoiGordo * 25 * fatorBoi);
  const componenteMilho = precise(rentMilho * 25 * fatorMilho);
  const componenteSoja = precise(rentSoja * 25 * fatorSoja);

  const somaComponentes = precise(
    componenteBoi + componenteMilho + componenteSoja,
  );
  const descontoArrendamento = precise(somaComponentes * fatorArrendamento);
  const vusBruto = somaComponentes - descontoArrendamento;

  // **Resultado final com precisão de 2 casas decimais**
  const vusFinal = precise(vusBruto, 2);

  const currentDate = new Date().toISOString().split("T")[0];
  const [year, month, day] = currentDate.split("-");
  const brazilianDate = `${day}/${month}/${year}`;

  return [
