      json: {
        ativo: "VUS",
        data: brazilianDate,
        valor: vusFinal,
        componentes: {
          boi_gordo_35: Math.round(componenteBoi * 100) / 100,
          milho_30: Math.round(componenteMilho * 100) / 100,
          soja_35: Math.round(componenteSoja * 100) / 100,
          base_calculo: Math.round(somaComponentes * 100) / 100,
          desconto_arrendamento: Math.round(descontoArrendamento * 100) / 100,
          resultado_final: vusFinal,
        },
        fatores_utilizados: {
          fator_boi: fatorBoi,
          fator_milho: fatorMilho,
          fator_soja: fatorSoja,
          fator_arrendamento: fatorArrendamento,
        },
        valores_originais: {
          rent_boi_gordo: Math.round(rentBoiGordo * 100) / 100,
          rent_milho: Math.round(rentMilho * 100) / 100,
          rent_soja: Math.round(rentSoja * 100) / 100,
        },
        formula:
          "=((C5*25*B8+E5*25*D8+G5*25*F8)-(C5*25*B8+E5*25*D8+G5*25*F8)*F7)",
        moeda: "BRL",
        fonte: "Cálculo UCS",
        timestamp: new Date().toISOString(),
        status: "sucesso",
        documentId: currentDate, // ← ADICIONAR AQUI! ✅
        verificacao_calculo: {
          vus_bruto: vusBruto,
          vus_final: vusFinal,
          diferenca_arredondamento: vusBruto - vusFinal,
          precisao_utilizada: "Replicando exatamente a planilha Excel",
          metodo_calculo:
            "Multiplica por 25 primeiro, depois aplica fatores (como Excel)",
        },
      },
    },
  ];
