  const vusData = $("💾 Salvar VUS").first()?.json || null;
  const vmadData = $("💾 Salvar Vmad").first()?.json || null;
  const carbonoCRSData = $("💾 Salvar Carbono_CRS").first()?.json || null;
  const aguaCRSData = $("💾 Salvar Agua_CRS").first()?.json || null;

  // Verificar se todos os dados estão disponíveis
  if (!vusData || !vmadData || !carbonoCRSData || !aguaCRSData) {
    return [
      {
        json: {
          erro: "Dados insuficientes para calcular Valor_Uso_Solo",
          dados_faltando: {
            vus: !vusData,
            vmad: !vmadData,
            carbono_crs: !carbonoCRSData,
            agua_crs: !aguaCRSData,
          },
          timestamp: new Date().toISOString(),
          status: "erro",
        },
      },
    ];
  }

  // Extrair valores
  const valorVUS = parseFloat(vusData.valor) || 0;
  const valorVmad = parseFloat(vmadData.valor) || 0;
  const valorCarbonoCRS = parseFloat(carbonoCRSData.valor) || 0;
  const valorAguaCRS = parseFloat(aguaCRSData.valor) || 0;

  // Calcular Valor_Uso_Solo
  const valorUsoSolo = valorVUS + valorVmad + valorCarbonoCRS + valorAguaCRS;

  // Calcular porcentagens de cada componente
  const percentualVUS = valorUsoSolo > 0 ? (valorVUS / valorUsoSolo) * 100 : 0;
  const percentualVmad =
    valorUsoSolo > 0 ? (valorVmad / valorUsoSolo) * 100 : 0;
  const percentualCarbonoCRS =
    valorUsoSolo > 0 ? (valorCarbonoCRS / valorUsoSolo) * 100 : 0;
  const percentualAguaCRS =
    valorUsoSolo > 0 ? (valorAguaCRS / valorUsoSolo) * 100 : 0;

  // Preparar dados para salvar
  const currentDate = new Date().toISOString().split("T")[0];
